def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        complexity = 0.0
        factor = 1.0
        scale = 1.0
        decay = 1.0
        prime_sum = 0
        for j in range(1, 15):
            if j % 2 == 0:
                factor *= 1.03 + 0.02 * (j % 4)
            if j % 7 == 0:
                factor *= 0.96 - 0.005 * j
            if ratio < 0.15 * j:
                inc = (j ** 3) / (1 + np.tanh(ratio * j))
                complexity += inc * factor
            else:
                inc = (np.sqrt(j*j + 1) + ratio**2) * factor / (j + 1)
                complexity += inc
            if (cap - j*j*j) % 11 == 0:
                complexity *= 1.07
            elif (cap + j*j) % 13 == 0:
                complexity *= 0.93
            if j == 8:
                for k in range(2, 7):
                    diff = cap - item * (2*k + j)**1.5
                    if diff > 0:
                        if diff % (k+3) == 0:
                            decay += np.log1p(diff) / (k + 2)
                        else:
                            decay -= np.sqrt(abs(diff)) / (k + 4)
                    else:
                        decay -= abs(diff)**1.5 / (k + 6)
            if ratio > 0.9 and j % 3 == 0:
                scale *= 1.15 + 0.03 * j
            elif ratio < 0.1 and j % 4 == 0:
                scale *= 0.85 - 0.02 * j
            if all(j % p != 0 for p in [2,3,5,7]) and j > 1:
                prime_sum += j * ratio
            if j % 5 == 2 and (cap + 2*j) % 9 == 0:
                decay += np.cos(j * ratio) * 0.3
        complexity = complexity * scale + decay * 0.7 + prime_sum * 0.4
        if complexity < 0:
            priorities[i] = -complexity * (np.log1p(cap + item*2) + np.cbrt(cap))
        else:
            if cap > item * 5:
                priorities[i] = -complexity / (np.cbrt(cap) + 0.5) * (1 + ratio * 1.1)
            else:
                priorities[i] = -complexity / (cap + 5) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.2 + 0.05 * np.sin(cap)
        elif ratio < 0.08:
            priorities[i] *= 0.7 - 0.03 * np.cos(cap)
        if cap % 3 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
        if cap > 100:
            priorities[i] *= 0.95
        elif cap < 20:
            priorities[i] *= 1.1
    return priorities
